#!/usr/bin/env node
// tools/build_browser_bundle.js
// Bundles dist/{lexer,parser,codegen,checker,stdlib}.js into a single
// browser-compatible IIFE: demo/axon.compiler.js
// Exposes: window.AxonCompiler.compile(src) → { js, errors, warnings }
//          window.AxonCompiler.check(src)   → { warnings }
//          window.AxonCompiler.version      → "0.9.5"

const fs   = require('fs')
const path = require('path')

const ROOT = path.join(__dirname, '..')
const DIST = path.join(ROOT, 'dist')
const OUT  = path.join(ROOT, 'demo', 'axon.compiler.js')

// ── Strip CommonJS wrapper from a dist file ───────────────────────────────────
function stripCJS(src, removedExports) {
  let out = src
  // Remove "use strict";
  out = out.replace(/"use strict";\n/, '')
  // Remove __createBinding / __setModuleDefault / __importStar boilerplate
  out = out.replace(/var __createBinding[\s\S]*?}\)\);\n/g, '')
  out = out.replace(/var __setModuleDefault[\s\S]*?}\);\n/g, '')
  out = out.replace(/var __importStar[\s\S]*?}\)\);\n/g, '')
  // Remove Object.defineProperty(exports, "__esModule", { value: true });
  out = out.replace(/Object\.defineProperty\(exports, "__esModule", \{ value: true \}\);\n/, '')
  // Promote exports.AXON_STDLIB = `template`; → const AXON_STDLIB = `template`;
  // (must run before the blanket exports removal below)
  out = out.replace(/exports\.AXON_STDLIB = (`[\s\S]*?`);\n/, 'const AXON_STDLIB = $1;\n')
  // Remove ALL remaining exports.* assignments (void 0 inits, class re-exports, chained assignments)
  // Split into lines and drop any line that starts with "exports."
  out = out.split('\n').filter(line => !line.trimStart().startsWith('exports.')).join('\n')
  // Remove const x = require('./y.js'); lines
  out = out.replace(/const \w+ = require\("\.\/\w+\.js"\);\n/g, '')
  // Replace ModuleRef.ClassName with ClassName (e.g. stdlib_js_1.AXON_STDLIB → AXON_STDLIB)
  for (const ref of removedExports) {
    const re = new RegExp(`${ref}\\.`, 'g')
    out = out.replace(re, '')
  }
  return out.trim()
}

// ── Read each dist module, strip CJS, collect source ─────────────────────────
const stdlib  = stripCJS(fs.readFileSync(path.join(DIST, 'stdlib.js'),  'utf8'), [])
const lexer   = stripCJS(fs.readFileSync(path.join(DIST, 'lexer.js'),   'utf8'), [])
const parser  = stripCJS(fs.readFileSync(path.join(DIST, 'parser.js'),  'utf8'), [])
const codegen = stripCJS(fs.readFileSync(path.join(DIST, 'codegen.js'), 'utf8'), ['stdlib_js_1'])
const checker = stripCJS(fs.readFileSync(path.join(DIST, 'checker.js'), 'utf8'), [])

// ── Build the IIFE ────────────────────────────────────────────────────────────
const bundle = `// Axon v0.9.5 — Browser compiler bundle
// Generated by tools/build_browser_bundle.js
// API: AxonCompiler.compile(src) → { js, errors, warnings }
//      AxonCompiler.check(src)   → { warnings }
//      AxonCompiler.version      → "0.9.5"
(function (global) {
  "use strict";

  // ── stdlib ──────────────────────────────────────────────────────────────────
  ${stdlib}

  // ── lexer ───────────────────────────────────────────────────────────────────
  ${lexer}

  // ── parser ──────────────────────────────────────────────────────────────────
  ${parser}

  // ── codegen ─────────────────────────────────────────────────────────────────
  ${codegen}

  // ── checker ─────────────────────────────────────────────────────────────────
  ${checker}

  // ── Public API ──────────────────────────────────────────────────────────────
  // v0.9.5: compile() uses multi-error parser — returns all parse errors at once
  function compile(source) {
    try {
      const tokens = new Lexer(source).tokenize()
      const { ast, errors: parseErrs } = new Parser(tokens).parse()
      const errors = parseErrs.map(e => ({
        message: e.message, line: e.line ?? 1, col: e.col ?? 1, kind: 'parse'
      }))
      if (errors.length > 0) return { js: null, errors, warnings: [] }
      const diags = new Checker().check(ast)
      const warnings = diags.map(d => ({
        severity: d.severity, message: d.message, line: d.line, col: d.col ?? 1,
      }))
      const js = new Codegen().generate(ast)
      return { js, errors: [], warnings }
    } catch (e) {
      return { js: null, errors: [{ message: String(e), line: 1, col: 1, kind: 'error' }], warnings: [] }
    }
  }

  function check(source) {
    try {
      const tokens = new Lexer(source).tokenize()
      const { ast, errors: parseErrs } = new Parser(tokens).parse()
      if (parseErrs.length > 0) {
        return { warnings: [], errors: parseErrs.map(e => ({ message: e.message, line: e.line, col: e.col })) }
      }
      const diags = new Checker().check(ast)
      return {
        warnings: diags.map(d => ({ severity: d.severity, message: d.message, line: d.line, col: d.col ?? 1 })),
        errors: []
      }
    } catch (e) {
      return { warnings: [], errors: [{ message: String(e), line: 1, col: 1 }] }
    }
  }

  global.AxonCompiler = { compile, check, version: "0.9.5" }

})(typeof window !== 'undefined' ? window : typeof globalThis !== 'undefined' ? globalThis : this);
`

fs.writeFileSync(OUT, bundle, 'utf8')
const lines = bundle.split('\n').length
console.log(`✓ axon.compiler.js  ${lines} lines  →  demo/axon.compiler.js`)
